// Middleware factory – returns a middleware that checks for required role(s)
function authorize(roles = []) {
  if (typeof roles === 'string') roles = [roles];
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Unauthorized' });
    }
    if (roles.length && !roles.includes(req.user.role)) {
      return res.status(403).json({ error: 'Forbidden: insufficient permissions' });
    }
    next();
  };
}

// Usage:
app.get('/admin', authenticateToken, authorize('admin'), (req, res) => {
  res.send('Admin only');
});

app.get('/profile', authenticateToken, authorize(['user', 'admin']), (req, res) => {
  res.send('User profile');
});
```

Sometimes you need to check if a user owns a resource. For example, a user can only edit their own post.

This requires checking the user ID from the token/session against the resource's owner ID.

```javascript
app.delete('/posts/:id', authenticateToken, async (req, res) => {
  const post = await Post.findById(req.params.id);
  if (!post) return res.status(404).json({ error: 'Post not found' });
  if (post.userId !== req.user.userId && req.user.role !== 'admin') {
    return res.status(403).json({ error: 'You can only delete your own posts' });
  }
  await post.remove();
  res.sendStatus(204);
});
```
